import React, { useState, useMemo, useRef } from "react";
import { Copy, Check, Download, Monitor, Smartphone, Plus, Trash2, Upload, X } from "lucide-react";

/* ---------------- Maax Unicase Bold, embedded as a data URI so the
   headline can use the real brand font. Only this one weight/style is
   embedded (≈37KB base64) — small enough to stay inside Gmail's ~102KB
   clip limit even with a couple of release cards. Nunito is loaded from
   Google Fonts instead of embedded, since the variable TTF alone is
   ~275KB — far too heavy to inline into an email. ---------------- */
const MAAX_B64 = "";

const FONT_FACE_MAAX = `@font-face{font-family:'Maax Unicase';src:url(data:font/woff2;base64,${MAAX_B64}) format('woff2');font-weight:700;font-style:normal;font-display:swap;}`;
const NUNITO_LINK = "https://fonts.googleapis.com/css2?family=Nunito:ital,wght@0,400;0,600;0,700;0,800;1,400&display=swap";

// Duetti's own logo, embedded once so it doesn't need to be re-uploaded
// for every pitch. Downsized/quantized to ~18KB so it barely dents
// Gmail's ~102KB clip budget. Swap or clear it in the form any time.
const DUETTI_LOGO_DATA_URI = "data:image/png;base64,";

// DSP logos, embedded the same way — pick one from the dropdown instead
// of hunting down and uploading a logo file every time. Only the ONE
// selected logo ever ends up in a given email, so these don't add up
// against Gmail's per-email size limit — that only cares about whichever
// single logo is actually used.
const DSP_LOGOS = {
  "Spotify": "data:image/png;base64,",
  "Apple Music": "data:image/png;base64,",
  "TIDAL": "data:image/png;base64,",
  "Audiomack": "data:image/png;base64,",
  "YouTube Music": "data:image/png;base64,",
  "Pandora": "data:image/png;base64,",
  "SoundCloud": "data:image/png;base64,",
  "Deezer": "data:image/png;base64,",
  "Amazon Music": "data:image/png;base64,",
  "SiriusXM": "data:image/png;base64,",
};
const DSP_NAMES = Object.keys(DSP_LOGOS);

// Some logos read visually larger or smaller than others even at the same
// pixel height (denser wordmarks, different letterforms). This lets any
// single one be nudged without affecting the rest.
const DSP_LOGO_SCALE = {
  Audiomack: 0.8,
};

// ---------------- helpers ----------------

const escapeHtml = (str = "") =>
  String(str)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");

const escapeAttr = (str = "") => escapeHtml(str).replace(/\n/g, " ");

// escape first, then turn **bold** into <strong> so copy typed in the
// form (e.g. "Hey **[Contact Name]**,") can carry emphasis into the email
const richText = (str = "") =>
  escapeHtml(str).replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>");

const paragraphs = (text = "") =>
  text
    .split("\n")
    .map((l) => l.trim())
    .filter(Boolean);

// Reads an uploaded image file, downsizes it, and returns a compact
// base64 data URL — keeps embedded logos/cover art from blowing past
// Gmail's ~102KB clip limit the way an unresized phone photo would.
function fileToResizedDataUrl(file, maxDim = 480, quality = 0.82) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onerror = () => reject(new Error("Could not read file"));
    reader.onload = () => {
      const img = new Image();
      img.onerror = () => reject(new Error("Could not decode image"));
      img.onload = () => {
        let { width, height } = img;
        if (width > maxDim || height > maxDim) {
          const scale = maxDim / Math.max(width, height);
          width = Math.round(width * scale);
          height = Math.round(height * scale);
        }
        const canvas = document.createElement("canvas");
        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext("2d");
        ctx.drawImage(img, 0, 0, width, height);
        resolve(canvas.toDataURL(file.type === "image/png" ? "image/png" : "image/jpeg", quality));
      };
      img.src = reader.result;
    };
    reader.readAsDataURL(file);
  });
}

// bulletproof concentric-ring mark, built from nested tables so it
// never depends on an image or SVG loading
function ringMark(primary, size = 34) {
  const s1 = size,
    s2 = Math.round(size * 0.62),
    s3 = Math.round(size * 0.26);
  return `<table role="presentation" cellpadding="0" cellspacing="0" style="width:${s1}px;height:${s1}px;"><tr><td align="center" valign="middle" style="width:${s1}px;height:${s1}px;border-radius:50%;border:2px solid ${primary};">
    <table role="presentation" cellpadding="0" cellspacing="0" style="width:${s2}px;height:${s2}px;"><tr><td align="center" valign="middle" style="width:${s2}px;height:${s2}px;border-radius:50%;border:2px solid ${primary};">
      <table role="presentation" cellpadding="0" cellspacing="0" style="width:${s3}px;height:${s3}px;"><tr><td style="width:${s3}px;height:${s3}px;border-radius:50%;background-color:${primary};font-size:1px;line-height:1px;">&nbsp;</td></tr></table>
    </td></tr></table>
  </td></tr></table>`;
}

function metaRow(label, value, sand) {
  if (!value) return "";
  return `<tr><td style="padding:0 0 5px 0;">
    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" class="copy-box" data-copy="${escapeAttr(
      value
    )}" style="background-color:${sand};border-radius:6px;cursor:pointer;">
      <tr><td style="padding:5px 9px;">
        <div style="font-family:'Nunito',Verdana,Geneva,sans-serif;font-size:8.5px;font-weight:700;letter-spacing:0.4px;color:#7C8F84;text-transform:uppercase;">${escapeHtml(
          label
        )}</div>
        <div style="font-family:'Nunito',Verdana,Geneva,sans-serif;font-size:12px;font-weight:700;color:#1F2E27;margin-top:1px;">${escapeHtml(
          value
        )}</div>
      </td></tr>
    </table>
  </td></tr>`;
}

function releaseCardHtml(r, primary, accent, sand) {
  const artistLine = r.album
    ? `${escapeHtml(r.artist)} <span style="color:#8A9691;">&middot; from ${escapeHtml(r.album)}</span>`
    : escapeHtml(r.artist);

  return `<tr><td style="padding:0 0 20px 0;">
    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="border:1.5px solid ${primary};border-radius:12px;">
      <tr><td style="padding:24px 24px 20px 24px;">
        <table role="presentation" width="100%" cellpadding="0" cellspacing="0">
          <tr>
            <td valign="top" align="left">
              <div style="font-family:'Nunito',Verdana,Geneva,sans-serif;font-size:20px;font-weight:800;color:${primary};">${escapeHtml(
                r.title
              )}</div>
              <div style="font-family:'Nunito',Verdana,Geneva,sans-serif;font-size:13px;font-weight:600;color:#5B6B63;margin-top:3px;">${artistLine}</div>
            </td>
            <td valign="top" align="right" style="white-space:nowrap;">
              <table role="presentation" cellpadding="0" cellspacing="0"><tr><td style="background-color:${accent};border-radius:20px;padding:6px 14px;">
                <span style="font-family:'Nunito',Verdana,Geneva,sans-serif;font-size:10.5px;font-weight:800;letter-spacing:0.5px;color:${primary};text-transform:uppercase;white-space:nowrap;">${escapeHtml(
                  r.genre
                )}</span>
              </td></tr></table>
            </td>
          </tr>
        </table>
        <table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="margin-top:16px;">
          <tr>
            ${
              r.coverArtUrl
                ? `<td valign="top" width="50%" style="width:50%;padding-right:12px;">
                    <img src="${escapeAttr(r.coverArtUrl)}" alt="${escapeAttr(
                    r.title
                  )} cover art" style="display:block;width:100%;height:auto;border-radius:10px;background-color:${sand};" />
                  </td>`
                : ""
            }
            <td valign="top" style="width:${r.coverArtUrl ? "50%" : "100%"};">
              <table role="presentation" width="100%" cellpadding="0" cellspacing="0">
                ${metaRow("Release date", r.releaseDate, sand)}
                ${metaRow("Label", r.label, sand)}
                ${metaRow("UPC", r.upc, sand)}
                ${metaRow("ISRC", r.isrc, sand)}
              </table>
            </td>
          </tr>
        </table>
        <div style="font-family:'Nunito',Verdana,Geneva,sans-serif;font-size:10px;font-weight:800;letter-spacing:0.6px;color:#7C8F84;text-transform:uppercase;margin:10px 0 4px 0;">Description</div>
        <p style="margin:0 0 18px 0;font-family:'Nunito',Verdana,Geneva,sans-serif;font-size:14px;line-height:21px;color:#3A443F;">${richText(
          r.description
        )}</p>
        <table role="presentation" cellpadding="0" cellspacing="0"><tr><td style="background-color:${primary};border-radius:20px;">
          <a href="${escapeAttr(
            r.listeningLink
          )}" style="display:inline-block;padding:11px 22px;font-family:'Nunito',Verdana,Geneva,sans-serif;font-size:12.5px;font-weight:800;letter-spacing:0.4px;color:#FFFFFF;text-decoration:none;text-transform:uppercase;">&#9654;&nbsp; Listening link</a>
        </td></tr></table>
      </td></tr>
    </table>
  </td></tr>`;
}

function buildEmailHtml(f, { forPreview = false } = {}) {
  const primary = f.primaryColor || "#17422C";
  const accent = f.accentColor || "#D0F148";
  const cream = "#F7F4EC";
  const sand = "#F1F0E9";

  const logoCell = f.logoImageUrl
    ? `<img src="${escapeAttr(f.logoImageUrl)}" alt="${escapeAttr(
        f.companyName
      )}" height="28" style="display:block;height:28px;width:auto;" />`
    : `<span style="font-family:'Maax Unicase',Arial,Helvetica,sans-serif;font-weight:700;font-size:19px;letter-spacing:0.5px;color:${primary};text-transform:uppercase;">${escapeHtml(
        f.companyName
      )}</span>`;

  const introParas = paragraphs(f.introText)
    .map(
      (p) =>
        `<p style="margin:0 0 16px 0;font-family:'Nunito',Verdana,Geneva,sans-serif;font-size:15px;line-height:23px;color:#3A443F;">${richText(
          p
        )}</p>`
    )
    .join("\n            ");

  const releaseCards = f.releases.map((r) => releaseCardHtml(r, primary, accent, sand)).join("\n");

  const preheaderPad = Array(60).fill("&zwnj;&nbsp;").join("");

  return `<!DOCTYPE html>
<html lang="en" xmlns="http://www.w3.org/1999/xhtml">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<meta http-equiv="X-UA-Compatible" content="IE=edge">
<meta name="color-scheme" content="light">
<meta name="supported-color-schemes" content="light">
<title>${escapeHtml(f.subjectLine)}</title>
<link rel="stylesheet" href="${NUNITO_LINK}">
<style>
  ${FONT_FACE_MAAX}
  body, table, td, a { -webkit-text-size-adjust: 100%; -ms-text-size-adjust: 100%; }
  table, td { mso-table-lspace: 0pt; mso-table-rspace: 0pt; }
  img { -ms-interpolation-mode: bicubic; border: 0; height: auto; line-height: 100%; outline: none; text-decoration: none; }
  body { margin: 0; padding: 0; width: 100% !important; background-color: ${cream}; }
  .copy-box.copied td div:last-child::after { content: " ✓ copied"; color: ${primary}; font-weight: 700; }
  @media screen and (max-width: 600px) {
    .email-container { width: 100% !important; }
    .mobile-padding { padding-left: 20px !important; padding-right: 20px !important; }
    .headline { font-size: 26px !important; }
  }
</style>
</head>
<body style="margin:0;padding:0;background-color:${cream};">
  <div style="display:none;font-size:1px;color:${cream};line-height:1px;max-height:0;max-width:0;opacity:0;overflow:hidden;">
    ${escapeHtml(f.preheaderText)}${preheaderPad}
  </div>
  <center>
    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background-color:${cream};">
      <tr>
        <td align="center" style="padding:32px 12px;">
          <table role="presentation" class="email-container" width="600" cellpadding="0" cellspacing="0" style="width:600px;max-width:600px;">

            <tr>
              <td class="mobile-padding" style="padding:0 12px 22px 12px;">
                <table role="presentation" width="100%" cellpadding="0" cellspacing="0">
                  <tr>
                    <td valign="middle" align="left">${logoCell}</td>
                    <td valign="middle" align="right">${ringMark(primary, 34)}</td>
                  </tr>
                </table>
              </td>
            </tr>

            <tr>
              <td class="mobile-padding" style="padding:0 12px 22px 12px;">
                <div style="font-family:'Nunito',Verdana,Geneva,sans-serif;font-size:11px;font-weight:800;letter-spacing:1.4px;color:${primary};text-transform:uppercase;margin-bottom:8px;">Priority releases</div>
                ${
                  f.dspLogoUrl
                    ? `<img src="${escapeAttr(f.dspLogoUrl)}" alt="${escapeAttr(
                        f.dspName
                      )}" style="display:block;height:${Math.round(
                        42 * (DSP_LOGO_SCALE[f.dspName] || 1)
                      )}px;width:auto;" />`
                    : `<h1 class="headline" style="margin:0;font-family:'Maax Unicase',Arial,Helvetica,sans-serif;font-weight:700;font-size:34px;line-height:1.05;color:${primary};text-transform:uppercase;">For ${escapeHtml(
                        f.dspName
                      )}</h1>`
                }
                <div style="border-top:2.5px solid ${primary};margin:16px 0 20px 0;"></div>
                <p style="margin:0 0 16px 0;font-family:'Nunito',Verdana,Geneva,sans-serif;font-size:15px;line-height:23px;color:#3A443F;">Hey ${richText(
                  f.contactName
                )},</p>
                ${introParas}
              </td>
            </tr>

            <tr>
              <td class="mobile-padding" style="padding:0 12px;">
                <table role="presentation" width="100%" cellpadding="0" cellspacing="0">
                  ${releaseCards}
                </table>
              </td>
            </tr>

            <tr>
              <td class="mobile-padding" style="padding:4px 12px 28px 12px;">
                <p style="margin:0 0 20px 0;font-family:'Nunito',Verdana,Geneva,sans-serif;font-size:15px;line-height:23px;color:#3A443F;">${richText(
                  f.closingText
                )}</p>
                <p style="margin:0;font-family:'Nunito',Verdana,Geneva,sans-serif;font-size:15px;line-height:21px;color:#3A443F;">Best,<br>${escapeHtml(
                  f.senderName
                )}<br>${escapeHtml(f.companyName)}</p>
              </td>
            </tr>

            <tr>
              <td class="mobile-padding" style="padding:16px 12px 0 12px;border-top:1px solid #E3E0D5;">
                <table role="presentation" width="100%" cellpadding="0" cellspacing="0">
                  <tr>
                    <td align="left" style="font-family:'Nunito',Verdana,Geneva,sans-serif;font-size:11px;color:#9AA69E;">${escapeHtml(
                      f.footerLeftText
                    )}</td>
                    <td align="right" style="font-family:'Nunito',Verdana,Geneva,sans-serif;font-size:11px;color:#9AA69E;">${escapeHtml(
                      f.footerRightText
                    )}</td>
                  </tr>
                </table>
              </td>
            </tr>

          </table>
        </td>
      </tr>
    </table>
  </center>
  ${
    forPreview
      ? `<script>
    document.querySelectorAll('.copy-box').forEach(function (box) {
      box.addEventListener('click', function () {
        var val = box.getAttribute('data-copy');
        var done = function () {
          box.classList.add('copied');
          setTimeout(function () { box.classList.remove('copied'); }, 1100);
        };
        if (navigator.clipboard && navigator.clipboard.writeText) {
          navigator.clipboard.writeText(val).then(done).catch(done);
        } else {
          var ta = document.createElement('textarea');
          ta.value = val;
          document.body.appendChild(ta);
          ta.select();
          try { document.execCommand('copy'); } catch (e) {}
          document.body.removeChild(ta);
          done();
        }
      });
    });
  </script>`
      : ""
  }
</body>
</html>`;
}

