// ---------------- small UI atoms ----------------

function Field({ label, hint, children }) {
  return (
    <div style={{ marginBottom: 14 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline" }}>
        <label style={{ fontFamily: "Nunito, sans-serif", fontSize: 12, fontWeight: 700, color: "#17422C" }}>{label}</label>
        {hint && <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: 10.5, color: "#9AA69E" }}>{hint}</span>}
      </div>
      <div style={{ marginTop: 5 }}>{children}</div>
    </div>
  );
}

function CopyButton({ value }) {
  const [copied, setCopied] = useState(false);
  if (!value) return null;
  const copy = async () => {
    try {
      await navigator.clipboard.writeText(value);
      setCopied(true);
      setTimeout(() => setCopied(false), 1200);
    } catch (e) {
      console.error(e);
    }
  };
  return (
    <button
      type="button"
      onClick={copy}
      title="Copy value"
      style={{
        display: "flex",
        alignItems: "center",
        gap: 4,
        flexShrink: 0,
        border: `1px solid ${copied ? "#17422C" : "#E3E0D5"}`,
        background: copied ? "#17422C" : "#FFFFFF",
        color: copied ? "#FFFFFF" : "#5B6B63",
        borderRadius: 6,
        padding: "8px 9px",
        cursor: "pointer",
        fontFamily: "Nunito, sans-serif",
        fontSize: 11,
        fontWeight: 700,
      }}
    >
      {copied ? <Check size={13} /> : <Copy size={13} />}
      {copied ? "Copied" : "Copy"}
    </button>
  );
}

function ImageField({ label, hint, value, onChange }) {
  const fileRef = useRef(null);
  const [busy, setBusy] = useState(false);

  const handleFile = async (e) => {
    const file = e.target.files && e.target.files[0];
    e.target.value = "";
    if (!file) return;
    setBusy(true);
    try {
      const dataUrl = await fileToResizedDataUrl(file);
      onChange(dataUrl);
    } catch (err) {
      console.error(err);
    } finally {
      setBusy(false);
    }
  };

  return (
    <div style={{ marginBottom: 14 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline" }}>
        <label style={{ fontFamily: "Nunito, sans-serif", fontSize: 12, fontWeight: 700, color: "#17422C" }}>{label}</label>
        {hint && <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: 10.5, color: "#9AA69E" }}>{hint}</span>}
      </div>
      <div style={{ display: "flex", gap: 8, marginTop: 5, alignItems: "center" }}>
        <div
          style={{
            width: 40,
            height: 40,
            flexShrink: 0,
            borderRadius: 6,
            border: "1px solid #E3E0D5",
            background: value ? `url(${value}) center/cover no-repeat` : "#F1F0E9",
          }}
        />
        <input
          style={{ ...inputStyle, flex: 1 }}
          value={value && value.startsWith("data:") ? "(uploaded image)" : value}
          onChange={(e) => onChange(e.target.value)}
          placeholder="Paste an image URL…"
          readOnly={value && value.startsWith("data:")}
        />
        <button
          type="button"
          onClick={() => fileRef.current && fileRef.current.click()}
          style={{ display: "flex", alignItems: "center", gap: 5, fontFamily: "Nunito, sans-serif", fontSize: 12, fontWeight: 700, color: "#17422C", background: "#EFF3EC", border: "1px solid #17422C", borderRadius: 6, padding: "8px 10px", cursor: "pointer", whiteSpace: "nowrap" }}
        >
          <Upload size={13} />
          {busy ? "…" : "Upload"}
        </button>
        {value && (
          <button
            type="button"
            onClick={() => onChange("")}
            title="Remove image"
            style={{ display: "flex", border: "none", background: "none", cursor: "pointer", color: "#B5544A" }}
          >
            <X size={15} />
          </button>
        )}
        <input ref={fileRef} type="file" accept="image/*" onChange={handleFile} style={{ display: "none" }} />
      </div>
    </div>
  );
}

const inputStyle = {
  width: "100%",
  boxSizing: "border-box",
  fontFamily: "Nunito, sans-serif",
  fontSize: 13,
  color: "#1F2E27",
  background: "#FFFFFF",
  border: "1px solid #E3E0D5",
  borderRadius: 6,
  padding: "8px 10px",
  outline: "none",
};

function SectionTitle({ children }) {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 10, margin: "26px 0 12px 0" }}>
      <span style={{ fontFamily: "'Maax Unicase', Arial, sans-serif", fontSize: 13, fontWeight: 700, color: "#17422C", textTransform: "uppercase", letterSpacing: 0.4 }}>
        {children}
      </span>
      <div style={{ flex: 1, height: 1, background: "#E3E0D5" }} />
    </div>
  );
}

function ReleaseForm({ r, onChange, onRemove, canRemove, idx }) {
  const set = (k) => (e) => onChange({ ...r, [k]: e.target.value });
  return (
    <div style={{ border: "1px solid #E3E0D5", borderRadius: 10, padding: 14, marginBottom: 14, background: "#FFFFFF" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
        <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: 11, color: "#D0F148", background: "#17422C", borderRadius: 4, padding: "2px 7px" }}>
          release {idx + 1}
        </span>
        {canRemove && (
          <button onClick={onRemove} style={{ border: "none", background: "none", cursor: "pointer", color: "#B5544A", display: "flex", alignItems: "center", gap: 4, fontFamily: "Nunito, sans-serif", fontSize: 12 }}>
            <Trash2 size={13} /> Remove
          </button>
        )}
      </div>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
        <Field label="Track title">
          <input style={inputStyle} value={r.title} onChange={set("title")} />
        </Field>
        <Field label="Genre tag">
          <input style={inputStyle} value={r.genre} onChange={set("genre")} />
        </Field>
        <Field label="Artist(s)">
          <input style={inputStyle} value={r.artist} onChange={set("artist")} />
        </Field>
        <Field label="Album (optional)">
          <input style={inputStyle} value={r.album} onChange={set("album")} />
        </Field>
      </div>
      <ImageField label="Cover art" hint="optional — shown beside the metadata" value={r.coverArtUrl} onChange={(v) => onChange({ ...r, coverArtUrl: v })} />
      <div>
        <Field label="Release date">
          <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
            <input style={{ ...inputStyle, minWidth: 0, flex: 1 }} value={r.releaseDate} onChange={set("releaseDate")} />
            <CopyButton value={r.releaseDate} />
          </div>
        </Field>
        <Field label="Label">
          <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
            <input style={{ ...inputStyle, minWidth: 0, flex: 1 }} value={r.label} onChange={set("label")} />
            <CopyButton value={r.label} />
          </div>
        </Field>
        <Field label="UPC">
          <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
            <input style={{ ...inputStyle, minWidth: 0, flex: 1 }} value={r.upc} onChange={set("upc")} />
            <CopyButton value={r.upc} />
          </div>
        </Field>
        <Field label="ISRC">
          <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
            <input style={{ ...inputStyle, minWidth: 0, flex: 1 }} value={r.isrc} onChange={set("isrc")} />
            <CopyButton value={r.isrc} />
          </div>
        </Field>
      </div>
      <Field label="Description" hint="** for bold **">
        <textarea style={{ ...inputStyle, resize: "vertical", minHeight: 80 }} value={r.description} onChange={set("description")} />
      </Field>
      <Field label="Listening link">
        <input style={inputStyle} value={r.listeningLink} onChange={set("listeningLink")} />
      </Field>
    </div>
  );
}

export default function EmailGenerator() {
  const [f, setF] = useState(initial);
  const [view, setView] = useState("desktop");
  const [copied, setCopied] = useState(false);

  const set = (k) => (e) => setF((prev) => ({ ...prev, [k]: e.target.value }));

  const updateRelease = (id, updated) =>
    setF((prev) => ({ ...prev, releases: prev.releases.map((r) => (r.id === id ? updated : r)) }));

  const addRelease = () =>
    setF((prev) => ({
      ...prev,
      releases: [
        ...prev.releases,
        {
          id: `r${Date.now()}`,
          title: "New track",
          artist: "Artist name",
          album: "",
          coverArtUrl: "",
          genre: "Genre",
          releaseDate: "",
          label: prev.companyName,
          upc: "",
          isrc: "",
          description: "",
          listeningLink: "",
        },
      ],
    }));

  const removeRelease = (id) => setF((prev) => ({ ...prev, releases: prev.releases.filter((r) => r.id !== id) }));

  const html = useMemo(() => buildEmailHtml(f), [f]);
  const previewHtml = useMemo(() => buildEmailHtml(f, { forPreview: true }), [f]);
  const byteSize = useMemo(() => new Blob([html]).size, [html]);
  const kb = (byteSize / 1024).toFixed(1);
  const overLimit = byteSize > 102 * 1024;

  const copyHtml = async () => {
    try {
      await navigator.clipboard.writeText(html);
      setCopied(true);
      setTimeout(() => setCopied(false), 1800);
    } catch (e) {
      console.error(e);
    }
  };

  const downloadHtml = () => {
    const blob = new Blob([html], { type: "text/html" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `${(f.subjectLine || "pitch").toLowerCase().replace(/[^a-z0-9]+/g, "-").slice(0, 40)}.html`;
    document.body.appendChild(a);
    a.click();
    a.remove();
    URL.revokeObjectURL(url);
  };

  const preSub = f.subjectLine || "(no subject)";
  const prePre = f.preheaderText || "";

  return (
    <div style={{ background: "#F7F4EC", minHeight: "100vh", fontFamily: "Nunito, sans-serif" }}>
      <style>{`
        @import url('${NUNITO_LINK}');
        ${FONT_FACE_MAAX}
        ::selection { background: #D0F148; }
        input[type=color] { -webkit-appearance: none; border: none; padding: 0; width: 34px; height: 28px; border-radius: 6px; overflow: hidden; }
        input[type=color]::-webkit-color-swatch { border: 1px solid #E3E0D5; border-radius: 6px; }
      `}</style>

      {/* header */}
      <div style={{ borderBottom: "1px solid #E3E0D5", padding: "16px 26px", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <span style={{ fontFamily: "'Maax Unicase', Arial, sans-serif", fontSize: 19, fontWeight: 700, color: "#17422C", textTransform: "uppercase" }}>
            Pitch Builder
          </span>
          <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: 11, color: "#9AA69E" }}>DSP release-pitch emails</span>
        </div>
        <div style={{ display: "flex", gap: 10 }}>
          <button
            onClick={copyHtml}
            style={{ display: "flex", alignItems: "center", gap: 6, fontFamily: "Nunito, sans-serif", fontSize: 13, fontWeight: 700, color: "#17422C", background: "#FFFFFF", border: "1px solid #E3E0D5", borderRadius: 6, padding: "8px 14px", cursor: "pointer" }}
          >
            {copied ? <Check size={15} /> : <Copy size={15} />}
            {copied ? "Copied" : "Copy HTML"}
          </button>
          <button
            onClick={downloadHtml}
            style={{ display: "flex", alignItems: "center", gap: 6, fontFamily: "Nunito, sans-serif", fontSize: 13, fontWeight: 700, color: "#FFFFFF", background: "#17422C", border: "none", borderRadius: 6, padding: "8px 14px", cursor: "pointer" }}
          >
            <Download size={15} />
            Download .html
          </button>
        </div>
      </div>

      <div style={{ display: "flex", alignItems: "flex-start" }}>
        {/* form */}
        <div style={{ width: 440, flexShrink: 0, padding: "10px 26px 60px 26px", maxHeight: "calc(100vh - 62px)", overflowY: "auto" }}>
          <SectionTitle>Sender &amp; subject</SectionTitle>
          <Field label="Company / label name">
            <input style={inputStyle} value={f.companyName} onChange={set("companyName")} />
          </Field>
          <ImageField
            label="Logo image"
            hint="defaults to the Duetti logo"
            value={f.logoImageUrl}
            onChange={(v) => setF((prev) => ({ ...prev, logoImageUrl: v }))}
          />
          <Field label="DSP" hint="pick one, or type your own below">
            <select
              style={{ ...inputStyle, cursor: "pointer" }}
              value={DSP_NAMES.includes(f.dspName) ? f.dspName : ""}
              onChange={(e) => {
                const name = e.target.value;
                if (!name) return;
                setF((prev) => ({ ...prev, dspName: name, dspLogoUrl: DSP_LOGOS[name] }));
              }}
            >
              <option value="">Custom / other…</option>
              {DSP_NAMES.map((name) => (
                <option key={name} value={name}>
                  {name}
                </option>
              ))}
            </select>
          </Field>
          <Field label="DSP name" hint='used in "For {DSP}" if no logo'>
            <input style={inputStyle} value={f.dspName} onChange={set("dspName")} />
          </Field>
          <ImageField
            label="DSP logo"
            hint="auto-filled by the dropdown above, or upload your own"
            value={f.dspLogoUrl}
            onChange={(v) => setF((prev) => ({ ...prev, dspLogoUrl: v }))}
          />
          <div style={{ display: "flex", gap: 14 }}>
            <div style={{ flex: 1 }}>
              <Field label="Primary color">
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <input type="color" value={f.primaryColor} onChange={set("primaryColor")} />
                  <input style={{ ...inputStyle, width: 90 }} value={f.primaryColor} onChange={set("primaryColor")} />
                </div>
              </Field>
            </div>
            <div style={{ flex: 1 }}>
              <Field label="Accent color">
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <input type="color" value={f.accentColor} onChange={set("accentColor")} />
                  <input style={{ ...inputStyle, width: 90 }} value={f.accentColor} onChange={set("accentColor")} />
                </div>
              </Field>
            </div>
          </div>
          <Field label="Subject line" hint={`${f.subjectLine.length} chars`}>
            <input style={inputStyle} value={f.subjectLine} onChange={set("subjectLine")} />
          </Field>
          <Field label="Preheader" hint={`${f.preheaderText.length} chars`}>
            <input style={inputStyle} value={f.preheaderText} onChange={set("preheaderText")} />
          </Field>

          <SectionTitle>Message</SectionTitle>
          <Field label="Contact name" hint="** for bold **">
            <input style={inputStyle} value={f.contactName} onChange={set("contactName")} />
          </Field>
          <Field label="Intro paragraph" hint="new line = new paragraph, ** for bold **">
            <textarea style={{ ...inputStyle, resize: "vertical", minHeight: 110 }} value={f.introText} onChange={set("introText")} />
          </Field>
          <Field label="Closing line">
            <textarea style={{ ...inputStyle, resize: "vertical", minHeight: 50 }} value={f.closingText} onChange={set("closingText")} />
          </Field>
          <Field label="Your name (signature)">
            <input style={inputStyle} value={f.senderName} onChange={set("senderName")} />
          </Field>

          <SectionTitle>Releases</SectionTitle>
          {f.releases.map((r, i) => (
            <ReleaseForm
              key={r.id}
              r={r}
              idx={i}
              canRemove={f.releases.length > 1}
              onChange={(updated) => updateRelease(r.id, updated)}
              onRemove={() => removeRelease(r.id)}
            />
          ))}
          <button
            onClick={addRelease}
            style={{ display: "flex", alignItems: "center", gap: 6, width: "100%", justifyContent: "center", fontFamily: "Nunito, sans-serif", fontSize: 13, fontWeight: 700, color: "#17422C", background: "#EFF3EC", border: "1px dashed #17422C", borderRadius: 8, padding: "10px 14px", cursor: "pointer" }}
          >
            <Plus size={15} /> Add another release
          </button>

          <SectionTitle>Footer</SectionTitle>
          <Field label="Footer left text">
            <input style={inputStyle} value={f.footerLeftText} onChange={set("footerLeftText")} />
          </Field>
          <Field label="Footer right text">
            <input style={inputStyle} value={f.footerRightText} onChange={set("footerRightText")} />
          </Field>

          <div style={{ marginTop: 14, fontFamily: "'JetBrains Mono', monospace", fontSize: 11, color: overLimit ? "#B5544A" : "#8A9691" }}>
            {kb} KB {overLimit ? "— over Gmail's ~102KB clip limit. Trim a release or shorten copy." : "— under Gmail's ~102KB clip limit."}
          </div>
        </div>

        {/* preview */}
        <div style={{ flex: 1, padding: "10px 26px 60px 0" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 14 }}>
            <button
              onClick={() => setView("desktop")}
              style={{ display: "flex", alignItems: "center", gap: 6, fontFamily: "Nunito, sans-serif", fontSize: 12.5, fontWeight: 700, padding: "7px 12px", borderRadius: 6, border: "1px solid #E3E0D5", background: view === "desktop" ? "#17422C" : "#FFFFFF", color: view === "desktop" ? "#FFFFFF" : "#17422C", cursor: "pointer" }}
            >
              <Monitor size={14} /> Desktop
            </button>
            <button
              onClick={() => setView("mobile")}
              style={{ display: "flex", alignItems: "center", gap: 6, fontFamily: "Nunito, sans-serif", fontSize: 12.5, fontWeight: 700, padding: "7px 12px", borderRadius: 6, border: "1px solid #E3E0D5", background: view === "mobile" ? "#17422C" : "#FFFFFF", color: view === "mobile" ? "#FFFFFF" : "#17422C", cursor: "pointer" }}
            >
              <Smartphone size={14} /> Mobile
            </button>
          </div>

          <div style={{ border: "1px solid #E3E0D5", borderRadius: "10px 10px 0 0", background: "#FFFFFF", overflow: "hidden" }}>
            <div style={{ padding: "8px 14px", background: "#F1F0E9", borderBottom: "1px solid #E3E0D5", fontFamily: "'JetBrains Mono', monospace", fontSize: 10.5, color: "#9AA69E" }}>
              gmail inbox preview — {view}
            </div>
            {view === "desktop" ? (
              <div style={{ display: "flex", alignItems: "center", gap: 12, padding: "12px 16px" }}>
                <div style={{ width: 28, height: 28, borderRadius: "50%", background: f.primaryColor, flexShrink: 0, display: "flex", alignItems: "center", justifyContent: "center", color: f.accentColor, fontSize: 12, fontWeight: 700 }}>
                  {(f.companyName || "?").slice(0, 1).toUpperCase()}
                </div>
                <div style={{ width: 150, flexShrink: 0, fontFamily: "Arial, sans-serif", fontSize: 13.5, fontWeight: 700, color: "#202124", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
                  {f.companyName}
                </div>
                <div style={{ flex: 1, fontFamily: "Arial, sans-serif", fontSize: 13.5, color: "#202124", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
                  <span style={{ fontWeight: 700 }}>{preSub}</span>
                  <span style={{ color: "#5f6368" }}> {" – "}{prePre.slice(0, 100)}</span>
                </div>
                <div style={{ fontFamily: "Arial, sans-serif", fontSize: 12, color: "#5f6368", flexShrink: 0 }}>2:14 PM</div>
              </div>
            ) : (
              <div style={{ padding: "12px 16px" }}>
                <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 4 }}>
                  <div style={{ width: 22, height: 22, borderRadius: "50%", background: f.primaryColor, flexShrink: 0, display: "flex", alignItems: "center", justifyContent: "center", color: f.accentColor, fontSize: 10, fontWeight: 700 }}>
                    {(f.companyName || "?").slice(0, 1).toUpperCase()}
                  </div>
                  <div style={{ fontFamily: "Arial, sans-serif", fontSize: 13, fontWeight: 700, color: "#202124" }}>{f.companyName}</div>
                  <div style={{ marginLeft: "auto", fontFamily: "Arial, sans-serif", fontSize: 11.5, color: "#5f6368" }}>2:14 PM</div>
                </div>
                <div style={{ fontFamily: "Arial, sans-serif", fontSize: 13, fontWeight: 700, color: "#202124", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
                  {preSub}
                </div>
                <div style={{ fontFamily: "Arial, sans-serif", fontSize: 12.5, color: "#5f6368", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
                  {prePre.slice(0, 40)}
                </div>
              </div>
            )}
          </div>

          <div style={{ border: "1px solid #E3E0D5", borderTop: "none", borderRadius: "0 0 10px 10px", background: "#EDEAE0", padding: 18, display: "flex", justifyContent: "center" }}>
            <div style={{ width: view === "desktop" ? 640 : 375, transition: "width 0.2s ease", boxShadow: "0 6px 24px rgba(23,66,44,0.14)", borderRadius: view === "mobile" ? 18 : 4, overflow: "hidden", background: "#fff" }}>
              <iframe title="email-preview" srcDoc={previewHtml} style={{ width: "100%", height: 760, border: "none", display: "block" }} />
            </div>
          </div>

          <div style={{ marginTop: 12, fontFamily: "Nunito, sans-serif", fontSize: 12, color: "#8A9691", lineHeight: 1.5 }}>
            Maax Unicase is embedded for the "For {"{DSP}"}" headline — it'll show on Gmail desktop web, and fall back to bold uppercase Arial on the Gmail mobile app (which doesn't support custom fonts). Nunito loads from Google Fonts with the same fallback behavior. Either way the layout, spacing, and colors stay identical.
          </div>
        </div>
      </div>
    </div>
  );
}
